import{V as e,et as t,mt as n,tt as r}from"./chunks/framework.Bb5YUzRP.js";var i=JSON.parse(`{"title":"Testing Strategy","description":"Nodalite testing strategy: real integration tests over mocks, per-package testing approach, and Vitest configuration. ","frontmatter":{"description":"Nodalite testing strategy: real integration tests over mocks, per-package testing approach, and Vitest configuration. "},"headers":[],"relativePath":"guides/testing.md","filePath":"guides/testing.md","lastUpdated":1784063781000}`),a={name:`guides/testing.md`};function o(e,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[r(`<h1 id="testing-strategy" tabindex="-1">Testing Strategy <a class="header-anchor" href="#testing-strategy" aria-label="Permalink to “Testing Strategy”">​</a></h1><p>Nodalite&#39;s tests follow one rule: <strong>prefer a real integration test over a mocked one wherever it&#39;s cheap to run.</strong></p><h2 id="per-package-approach" tabindex="-1">Per-package approach <a class="header-anchor" href="#per-package-approach" aria-label="Permalink to “Per-package approach”">​</a></h2><h3 id="adapter-node" tabindex="-1">adapter-node <a class="header-anchor" href="#adapter-node" aria-label="Permalink to “adapter-node”">​</a></h3><p>Tests start a real <code>http.Server</code> on an OS-assigned port and hit it with a real <code>fetch()</code> — not a simulated request object.</p><h3 id="adapter-lambda" tabindex="-1">adapter-lambda <a class="header-anchor" href="#adapter-lambda" aria-label="Permalink to “adapter-lambda”">​</a></h3><p>Tests use realistic API Gateway v1/v2 event fixtures, not simplified stand-ins, so a real shape mismatch would actually fail.</p><h3 id="workers" tabindex="-1">workers <a class="header-anchor" href="#workers" aria-label="Permalink to “workers”">​</a></h3><p>Tests spawn real <code>worker_threads</code>, including a real crash-and-restart cycle with real timing — not a mocked <code>Worker</code> class.</p><h3 id="ml" tabindex="-1">ml <a class="header-anchor" href="#ml" aria-label="Permalink to “ml”">​</a></h3><p>Tests spin up a real local HTTP server to verify actual disk caching of downloaded model bytes. The ~270MB <code>onnxruntime-node</code> dependency is replaced with a fake <code>InferenceEngine</code> implementing the same two-method interface. Additional tests cover path traversal rejection, file size limit enforcement, extension validation, and ONNX magic-byte verification — all using real filesystem operations, not mocks.</p><h3 id="core" tabindex="-1">core <a class="header-anchor" href="#core" aria-label="Permalink to “core”">​</a></h3><p>Unit tests for the router, middleware compose, error handling, and validation logic, plus integration tests that exercise the full request pipeline.</p><h2 id="running-tests" tabindex="-1">Running tests <a class="header-anchor" href="#running-tests" aria-label="Permalink to “Running tests”">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#62687b;--shiki-dark:#818e99;"># All packages</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#62687b;--shiki-dark:#818e99;"># Single package</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -w</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @nodalite/core</span></span></code></pre></div><h2 id="why-not-mocked-tests" tabindex="-1">Why not mocked tests? <a class="header-anchor" href="#why-not-mocked-tests" aria-label="Permalink to “Why not mocked tests?”">​</a></h2><p>Mocking hides real problems:</p><ul><li>Changes in the runtime&#39;s <code>worker_threads</code> API that break your worker code</li><li>Differences between your simulated Lambda event and a real one</li><li>Timing issues that only show up with real network calls</li></ul><p>When a real dependency is genuinely too heavy (native binaries, large models), the code is still written against its real API — only the <em>test</em> uses a fake, so the logic under test (caching, dedup, warm reuse) is validated for real.</p>`,19)]])}var s=e(a,[[`render`,o]]);export{i as __pageData,s as default};